// Values returns every declared value in declaration order.
func (c EffectFuncStatContainer) Values() []EffectFuncStat {
	out := make([]EffectFuncStat, len(effectFuncStatValues))
	copy(out, effectFuncStatValues)
	return out
}

// Infos returns every declared value's metadata in declaration order.
func (c EffectFuncStatContainer) Infos() []EffectFuncStatInfo {
	out := make([]EffectFuncStatInfo, len(effectFuncStatValues))
	for i, v := range effectFuncStatValues {
		out[i] = effectFuncStatInfos[v]
	}
	return out
}

// Len returns the number of declared values.
func (c EffectFuncStatContainer) Len() int {
	return len(effectFuncStatValues)
}

// All iterates every declared value in declaration order.
func (c EffectFuncStatContainer) All() iter.Seq[EffectFuncStat] {
	return func(yield func(EffectFuncStat) bool) {
		for _, v := range effectFuncStatValues {
			if !yield(v) {
				return
			}
		}
	}
}

// FromWire converts a raw wire value, reporting whether it is declared.
func (c EffectFuncStatContainer) FromWire(w string) (EffectFuncStat, bool) {
	v := EffectFuncStat(w)
	_, ok := effectFuncStatInfos[v]
	return v, ok
}

// FromWireUnsafe converts a raw wire value, assuming it's declared.
func (c EffectFuncStatContainer) FromWireUnsafe(w string) EffectFuncStat {
	return EffectFuncStat(w)
}

// Parse resolves a value by name, case-insensitively.
func (c EffectFuncStatContainer) Parse(s string) (EffectFuncStat, error) {
	if v, ok := effectFuncStatByName[strings.ToLower(strings.TrimSpace(s))]; ok {
		return v, nil
	}
	var zero EffectFuncStat
	return zero, fmt.Errorf("unknown EffectFuncStat: %q", s)
}

